// Canonical spell list used to seed the wiki.
// Content is stored as JSON so the client can parse level, school, classes, description.

export const SPELLS = [
  // ── Cantrips (level 0) ────────────────────────────────────────────────────
  { name: 'Acid Splash', level: 0, school: 'Conjuration', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'You hurl a bubble of acid. Choose one or two creatures you can see within range. If you choose two, they must be within 5 feet of each other. A target must succeed on a Dexterity saving throw or take 1d6 acid damage.' },
  { name: 'Blade Ward', level: 0, school: 'Abjuration', castingTime: '1 action', range: 'Self', duration: '1 round', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You extend your hand and trace a sigil of warding in the air. Until the end of your next turn, you have resistance against bludgeoning, piercing, and slashing damage dealt by weapon attacks.' },
  { name: 'Chill Touch', level: 0, school: 'Necromancy', castingTime: '1 action', range: '120 feet', duration: '1 round', classes: ['Wizard', 'Sorcerer', 'Warlock'], description: 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack. On a hit, the target takes 1d8 necrotic damage and cannot regain hit points until the start of your next turn.' },
  { name: 'Dancing Lights', level: 0, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Bard', 'Artificer'], description: 'You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air for the duration. You can move the lights up to 60 feet as a bonus action.' },
  { name: 'Druidcraft', level: 0, school: 'Transmutation', castingTime: '1 action', range: '30 feet', duration: 'Instantaneous', classes: ['Druid'], description: 'You create a tiny, harmless sensory effect that predicts what the weather will be, causes a flower to bloom, lights or snuffs a candle, or cleans or soils an object no larger than 1 cubic foot.' },
  { name: 'Eldritch Blast', level: 0, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Instantaneous', classes: ['Warlock'], description: 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack. On a hit, the target takes 1d10 force damage. At higher levels you fire multiple beams simultaneously.' },
  { name: 'Fire Bolt', level: 0, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack. On a hit, the target takes 1d10 fire damage. Flammable objects hit by this spell ignite if they are not worn or carried.' },
  { name: 'Friends', level: 0, school: 'Enchantment', castingTime: '1 action', range: 'Self', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'For the duration, you have advantage on all Charisma checks directed at one creature of your choice that is not hostile toward you. When the spell ends, the creature realizes it was charmed and may become hostile.' },
  { name: 'Guidance', level: 0, school: 'Divination', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Druid'], description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check.' },
  { name: 'Light', level: 0, school: 'Evocation', castingTime: '1 action', range: 'Touch', duration: '1 hour', classes: ['Wizard', 'Cleric', 'Bard', 'Artificer'], description: 'You touch one object no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like.' },
  { name: 'Mage Hand', level: 0, school: 'Conjuration', castingTime: '1 action', range: '30 feet', duration: '1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard', 'Artificer'], description: 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration and can carry up to 10 pounds, manipulate objects, or open unlocked doors and containers.' },
  { name: 'Mending', level: 0, school: 'Transmutation', castingTime: '1 minute', range: 'Touch', duration: 'Instantaneous', classes: ['Wizard', 'Cleric', 'Druid', 'Bard', 'Artificer'], description: 'This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, or a torn cloak. As long as the break or tear is no larger than 1 foot in any dimension, you mend it.' },
  { name: 'Minor Illusion', level: 0, school: 'Illusion', castingTime: '1 action', range: '30 feet', duration: '1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again. A creature that uses its action to examine the sound or image can determine it is an illusion.' },
  { name: 'Poison Spray', level: 0, school: 'Conjuration', castingTime: '1 action', range: '10 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Druid'], description: 'You extend your hand toward a creature you can see within range and project a puff of noxious gas. The creature must succeed on a Constitution saving throw or take 1d12 poison damage.' },
  { name: 'Prestidigitation', level: 0, school: 'Transmutation', castingTime: '1 action', range: '10 feet', duration: 'Up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard', 'Artificer'], description: 'This spell is a minor magical trick that novice spellcasters use for practice. You create an instantaneous, harmless sensory effect, light or snuff a small flame, clean or soil an object, chill or warm material, or create a small mark or symbol.' },
  { name: 'Produce Flame', level: 0, school: 'Conjuration', castingTime: '1 action', range: 'Self', duration: '10 minutes', classes: ['Druid'], description: 'A flickering flame appears in your hand. It sheds bright light in a 10-foot radius. You can also hurl the flame as an attack, making a ranged spell attack. On a hit, the target takes 1d8 fire damage.' },
  { name: 'Ray of Frost', level: 0, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack. On a hit, it takes 1d8 cold damage and its speed is reduced by 10 feet until the start of your next turn.' },
  { name: 'Sacred Flame', level: 0, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Cleric'], description: 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.' },
  { name: 'Shillelagh', level: 0, school: 'Transmutation', castingTime: '1 bonus action', range: 'Touch', duration: '1 minute', classes: ['Druid'], description: 'The wood of a club or quarterstaff you are holding is imbued with nature\'s power. For the duration, you can use your spellcasting ability instead of Strength for attack and damage rolls using that weapon.' },
  { name: 'Shocking Grasp', level: 0, school: 'Evocation', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack. On a hit, the target takes 1d8 lightning damage and cannot take reactions until the start of its next turn.' },
  { name: 'Spare the Dying', level: 0, school: 'Necromancy', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Cleric'], description: 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.' },
  { name: 'Thaumaturgy', level: 0, school: 'Transmutation', castingTime: '1 action', range: '30 feet', duration: 'Up to 1 minute', classes: ['Cleric'], description: 'You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following: your voice booms, flames flicker, harmless tremors shudder, your eyes glow, you create an instantaneous sound, or you cause a door or window to fly open or slam shut.' },
  { name: 'Thorn Whip', level: 0, school: 'Transmutation', castingTime: '1 action', range: '30 feet', duration: 'Instantaneous', classes: ['Druid', 'Artificer'], description: 'You create a long, vine-like whip covered in thorns that lashes out at your command. Make a melee spell attack. On a hit, the target takes 1d6 piercing damage and is pulled up to 10 feet closer to you.' },
  { name: 'Toll the Dead', level: 0, school: 'Necromancy', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Cleric', 'Warlock', 'Wizard'], description: 'You point at one creature you can see within range, and the sound of a dolorous bell fills the air around it. The target must succeed on a Wisdom saving throw or take 1d8 necrotic damage. If the target is missing any of its hit points, it instead takes 1d12 necrotic damage.' },
  { name: 'True Strike', level: 0, school: 'Divination', castingTime: '1 action', range: '30 feet', duration: 'Concentration, up to 1 round', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target\'s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn\'t ended.' },
  { name: 'Vicious Mockery', level: 0, school: 'Enchantment', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Bard'], description: 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a Wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.' },

  // ── Level 1 ───────────────────────────────────────────────────────────────
  { name: 'Absorb Elements', level: 1, school: 'Abjuration', castingTime: '1 reaction', range: 'Self', duration: '1 round', classes: ['Wizard', 'Sorcerer', 'Druid', 'Ranger', 'Artificer'], description: 'The spell captures some of the incoming energy, lessening its effect on you and storing it for your next melee attack. You have resistance to the triggering damage type until the start of your next turn. Also, the first time you hit with a melee attack on your next turn, the target takes an extra 1d6 damage of the triggering type.' },
  { name: 'Alarm', level: 1, school: 'Abjuration', castingTime: '1 minute (ritual)', range: '30 feet', duration: '8 hours', classes: ['Wizard', 'Ranger', 'Artificer'], description: 'You set an alarm against unwanted intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot cube. Until the spell ends, an alarm alerts you whenever a Tiny or larger creature touches or enters the warded area.' },
  { name: 'Bless', level: 1, school: 'Enchantment', castingTime: '1 action', range: '30 feet', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Paladin'], description: 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.' },
  { name: 'Burning Hands', level: 1, school: 'Evocation', castingTime: '1 action', range: 'Self (15-foot cone)', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer'], description: 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a Dexterity saving throw. On a failed save, a creature takes 3d6 fire damage, or half as much on a successful one.' },
  { name: 'Charm Person', level: 1, school: 'Enchantment', castingTime: '1 action', range: '30 feet', duration: '1 hour', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard', 'Druid'], description: 'You attempt to charm a humanoid you can see within range. It must make a Wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails, it is charmed by you until the spell ends or until you or your companions do anything harmful to it.' },
  { name: 'Command', level: 1, school: 'Enchantment', castingTime: '1 action', range: '60 feet', duration: '1 round', classes: ['Cleric', 'Paladin'], description: 'You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. Choose from: Approach, Drop, Flee, Grovel, or Halt.' },
  { name: 'Comprehend Languages', level: 1, school: 'Divination', castingTime: '1 action (ritual)', range: 'Self', duration: '1 hour', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written.' },
  { name: 'Cure Wounds', level: 1, school: 'Evocation', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Bard', 'Paladin', 'Ranger'], description: 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.' },
  { name: 'Detect Magic', level: 1, school: 'Divination', castingTime: '1 action (ritual)', range: 'Self', duration: 'Concentration, up to 10 minutes', classes: ['Wizard', 'Sorcerer', 'Cleric', 'Druid', 'Bard', 'Paladin', 'Ranger', 'Artificer'], description: 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.' },
  { name: 'Disguise Self', level: 1, school: 'Illusion', castingTime: '1 action', range: 'Self', duration: '1 hour', classes: ['Wizard', 'Sorcerer', 'Bard', 'Artificer'], description: 'You make yourself — including your clothing, armor, weapons, and other belongings on your person — look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between.' },
  { name: 'Entangle', level: 1, school: 'Conjuration', castingTime: '1 action', range: '90 feet', duration: 'Concentration, up to 1 minute', classes: ['Druid'], description: 'Grasping weeds and vines sprout from the ground in a 20-foot square starting from a point within range. The area is difficult terrain for the duration. A creature in the area when you cast the spell must succeed on a Strength saving throw or be restrained by the entangling plants until the spell ends.' },
  { name: 'Faerie Fire', level: 1, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Druid', 'Bard'], description: 'Each object in a 20-foot cube within range is outlined in blue, green, or violet light. Any creature in the area when the spell is cast is also outlined in light if it fails a Dexterity saving throw. For the duration, objects and affected creatures shed dim light, and attack rolls against them have advantage.' },
  { name: 'Feather Fall', level: 1, school: 'Transmutation', castingTime: '1 reaction', range: '60 feet', duration: '1 minute', classes: ['Wizard', 'Sorcerer', 'Bard', 'Artificer'], description: 'Choose up to five falling creatures within range. A falling creature\'s rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet.' },
  { name: 'Fog Cloud', level: 1, school: 'Conjuration', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Druid', 'Ranger'], description: 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.' },
  { name: 'Goodberry', level: 1, school: 'Transmutation', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Druid', 'Ranger'], description: 'Up to ten berries appear in your hand and are infused with magic for the duration. A creature can use its action to eat one berry. Eating a berry restores 1 hit point, and the berry provides enough nourishment to sustain a creature for one day.' },
  { name: 'Guiding Bolt', level: 1, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: '1 round', classes: ['Cleric'], description: 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage.' },
  { name: 'Healing Word', level: 1, school: 'Evocation', castingTime: '1 bonus action', range: '60 feet', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Bard'], description: 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.' },
  { name: 'Heroism', level: 1, school: 'Enchantment', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Paladin'], description: 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to being frightened and gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns.' },
  { name: 'Identify', level: 1, school: 'Divination', castingTime: '1 minute (ritual)', range: 'Touch', duration: 'Instantaneous', classes: ['Wizard', 'Bard', 'Artificer'], description: 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement, and how many charges it has.' },
  { name: 'Inflict Wounds', level: 1, school: 'Necromancy', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Cleric'], description: 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.' },
  { name: 'Longstrider', level: 1, school: 'Transmutation', castingTime: '1 action', range: 'Touch', duration: '1 hour', classes: ['Wizard', 'Druid', 'Bard', 'Ranger', 'Artificer'], description: 'You touch a creature. The target\'s speed increases by 10 feet until the spell ends.' },
  { name: 'Mage Armor', level: 1, school: 'Abjuration', castingTime: '1 action', range: 'Touch', duration: '8 hours', classes: ['Wizard', 'Sorcerer'], description: 'You touch a willing creature who isn\'t wearing armor, and a protective magical force surrounds it until the spell ends. The target\'s base AC becomes 13 + its Dexterity modifier.' },
  { name: 'Magic Missile', level: 1, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer'], description: 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.' },
  { name: 'Protection from Evil and Good', level: 1, school: 'Abjuration', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 10 minutes', classes: ['Cleric', 'Paladin', 'Wizard', 'Warlock'], description: 'Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead. The protection grants several benefits: attack rolls against the target have disadvantage, the target can\'t be charmed, frightened, or possessed.' },
  { name: 'Sanctuary', level: 1, school: 'Abjuration', castingTime: '1 bonus action', range: '30 feet', duration: '1 minute', classes: ['Cleric', 'Artificer'], description: 'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell.' },
  { name: 'Shield', level: 1, school: 'Abjuration', castingTime: '1 reaction', range: 'Self', duration: '1 round', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.' },
  { name: 'Sleep', level: 1, school: 'Enchantment', castingTime: '1 action', range: '90 feet', duration: '1 minute', classes: ['Wizard', 'Sorcerer', 'Bard'], description: 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points.' },
  { name: 'Speak with Animals', level: 1, school: 'Divination', castingTime: '1 action (ritual)', range: 'Self', duration: '10 minutes', classes: ['Druid', 'Bard', 'Ranger'], description: 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at minimum, beasts can give you information about nearby locations and monsters.' },
  { name: "Tasha's Hideous Laughter", level: 1, school: 'Enchantment', castingTime: '1 action', range: '30 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Bard'], description: 'A creature of your choice that you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a Wisdom saving throw or fall prone, becoming incapacitated and unable to stand up for the duration.' },
  { name: 'Thunderwave', level: 1, school: 'Evocation', castingTime: '1 action', range: 'Self (15-foot cube)', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Druid', 'Bard'], description: 'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn\'t pushed.' },
  { name: 'Witch Bolt', level: 1, school: 'Evocation', castingTime: '1 action', range: '30 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock'], description: 'A beam of crackling, blue energy lances out toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack. On a hit, the target takes 1d12 lightning damage, and on each of your turns you can use your action to deal 1d12 lightning damage automatically.' },

  // ── Level 2 ───────────────────────────────────────────────────────────────
  { name: 'Aid', level: 2, school: 'Abjuration', castingTime: '1 action', range: '30 feet', duration: '8 hours', classes: ['Cleric', 'Paladin', 'Artificer'], description: "Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target's hit point maximum and current hit points increase by 5 for the duration." },
  { name: 'Alter Self', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Self', duration: 'Concentration, up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'You assume a different form. Choose one of the following options: Aquatic Adaptation, Change Appearance, or Natural Weapons (your unarmed strikes deal 1d6 bludgeoning, piercing, or slashing damage).' },
  { name: 'Barkskin', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 hour', classes: ['Druid', 'Ranger'], description: "You touch a willing creature. Until the spell ends, the target's skin has a rough, bark-like appearance, and the target's AC can't be less than 16, regardless of what kind of armor it is wearing." },
  { name: 'Blindness/Deafness', level: 2, school: 'Necromancy', castingTime: '1 action', range: '30 feet', duration: '1 minute', classes: ['Wizard', 'Sorcerer', 'Cleric', 'Bard'], description: "You can blind or deafen a foe. Choose one creature that you can see within range to make a Constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration." },
  { name: 'Calm Emotions', level: 2, school: 'Enchantment', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Bard'], description: 'You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a Charisma saving throw; a creature can choose to fail this saving throw. If a creature fails its saving throw, choose one of the following: suppress one effect causing the target to be charmed or frightened, or make the target indifferent about creatures it is hostile toward.' },
  { name: 'Cloud of Daggers', level: 2, school: 'Conjuration', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You fill the air in a 5-foot cube centered on a point you choose within range with spinning daggers. A creature takes 4d4 slashing damage when it enters the spell\'s area for the first time on a turn or starts its turn there.' },
  { name: 'Darkness', level: 2, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 10 minutes', classes: ['Wizard', 'Sorcerer', 'Warlock'], description: 'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can\'t see through this magical darkness.' },
  { name: 'Enhance Ability', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 hour', classes: ['Cleric', 'Druid', 'Bard', 'Sorcerer', 'Artificer'], description: 'You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects: Bear\'s Endurance (advantage on Con checks, +2d6 temp HP), Bull\'s Strength (advantage on Str checks, double carry capacity), Cat\'s Grace (advantage on Dex checks, no falling damage under 20 feet), Eagle\'s Splendor (advantage on Cha checks), Fox\'s Cunning (advantage on Int checks), or Owl\'s Wisdom (advantage on Wis checks).' },
  { name: 'Hold Person', level: 2, school: 'Enchantment', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Cleric', 'Druid', 'Bard'], description: 'Choose a humanoid that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.' },
  { name: 'Invisibility', level: 2, school: 'Illusion', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard', 'Artificer'], description: 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. The spell ends for a target that attacks or casts a spell.' },
  { name: 'Knock', level: 2, school: 'Transmutation', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Bard'], description: 'Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access. A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred.' },
  { name: 'Lesser Restoration', level: 2, school: 'Abjuration', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Bard', 'Paladin', 'Ranger', 'Artificer'], description: 'You touch a creature and can end either one disease or one condition afflicting it. The condition can be blinded, deafened, paralyzed, or poisoned.' },
  { name: 'Levitate', level: 2, school: 'Transmutation', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 10 minutes', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'One creature or loose object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The target can move only by pushing or pulling against a fixed object or surface within reach.' },
  { name: 'Mirror Image', level: 2, school: 'Illusion', castingTime: '1 action', range: 'Self', duration: '1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock'], description: 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions. Each time a creature targets you with an attack, roll a d20 to determine whether the attack instead targets one of your duplicates.' },
  { name: 'Misty Step', level: 2, school: 'Conjuration', castingTime: '1 bonus action', range: 'Self', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Paladin'], description: 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.' },
  { name: 'Moonbeam', level: 2, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Druid'], description: 'A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder. When a creature enters the spell\'s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a Constitution saving throw, taking 2d10 radiant damage on a failed save.' },
  { name: 'Pass without Trace', level: 2, school: 'Abjuration', castingTime: '1 action', range: 'Self', duration: 'Concentration, up to 1 hour', classes: ['Druid', 'Ranger'], description: 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can\'t be tracked except by magical means.' },
  { name: 'Ray of Enfeeblement', level: 2, school: 'Necromancy', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Warlock'], description: 'A black beam of enervating energy springs from your finger toward a creature within range. Make a ranged spell attack. On a hit, the target deals only half damage with weapon attacks that use Strength until the spell ends.' },
  { name: 'Scorching Ray', level: 2, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer'], description: 'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several. Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.' },
  { name: 'Shatter', level: 2, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much on a successful one.' },
  { name: 'Silence', level: 2, school: 'Illusion', castingTime: '1 action (ritual)', range: '120 feet', duration: 'Concentration, up to 10 minutes', classes: ['Cleric', 'Bard', 'Ranger'], description: 'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it. Casting a spell that includes a verbal component is impossible there.' },
  { name: 'Spider Climb', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Artificer'], description: 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed.' },
  { name: 'Spiritual Weapon', level: 2, school: 'Evocation', castingTime: '1 bonus action', range: '60 feet', duration: '1 minute', classes: ['Cleric'], description: 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.' },
  { name: 'Suggestion', level: 2, school: 'Enchantment', castingTime: '1 action', range: '30 feet', duration: 'Concentration, up to 8 hours', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. The suggestion must be worded in such a manner as to make the course of action sound reasonable.' },
  { name: 'Warding Bond', level: 2, school: 'Abjuration', castingTime: '1 action', range: 'Touch', duration: '1 hour', classes: ['Cleric', 'Paladin'], description: 'This spell wards a willing creature you touch and creates a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and has resistance to all damage. Also, each time it takes damage, you take the same amount of damage.' },

  // ── Level 3 ───────────────────────────────────────────────────────────────
  { name: 'Animate Dead', level: 3, school: 'Necromancy', castingTime: '1 minute', range: '10 feet', duration: 'Instantaneous', classes: ['Wizard', 'Cleric'], description: 'This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature (skeleton or zombie). The creature obeys your verbal commands.' },
  { name: 'Bestow Curse', level: 3, school: 'Necromancy', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Cleric', 'Bard'], description: 'You touch a creature, and that creature must succeed on a Wisdom saving throw or become cursed for the duration of the spell. Choose one of the following curse options: disadvantage on ability checks and saving throws for one ability score, disadvantage on attack rolls against you, must make a Wisdom saving throw each turn or waste its action, or take an extra 1d8 necrotic damage from your attacks.' },
  { name: 'Call Lightning', level: 3, school: 'Conjuration', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 10 minutes', classes: ['Druid'], description: 'A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see directly above you. When you cast the spell, choose a point you can see under the cloud. A bolt of lightning flashes down to that point. Each creature within 5 feet of that point must make a Dexterity saving throw, taking 3d10 lightning damage on a failed save.' },
  { name: 'Counterspell', level: 3, school: 'Abjuration', castingTime: '1 reaction', range: '60 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Warlock'], description: 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a success, the creature\'s spell fails.' },
  { name: 'Daylight', level: 3, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: '1 hour', classes: ['Cleric', 'Druid', 'Sorcerer', 'Paladin', 'Ranger'], description: 'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet. If you chose a point on an object you are holding or one that isn\'t being worn or carried, the light shines from the object and moves with it.' },
  { name: 'Dispel Magic', level: 3, school: 'Abjuration', castingTime: '1 action', range: '120 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Cleric', 'Druid', 'Bard', 'Paladin', 'Artificer'], description: 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a successful check, the spell ends.' },
  { name: 'Fear', level: 3, school: 'Illusion', castingTime: '1 action', range: 'Self (30-foot cone)', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You project a phantasmal image of a creature\'s worst fears. Each creature in a 30-foot cone must succeed on a Wisdom saving throw or drop whatever it is holding and become frightened for the duration. While frightened by this spell, a creature must take the Dash action and move away from you by the safest available route.' },
  { name: 'Fireball', level: 3, school: 'Evocation', castingTime: '1 action', range: '150 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer'], description: 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a Dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.' },
  { name: 'Fly', level: 3, school: 'Transmutation', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 10 minutes', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Artificer'], description: 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.' },
  { name: 'Haste', level: 3, school: 'Transmutation', castingTime: '1 action', range: '30 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Artificer'], description: 'Choose a willing creature that you can see within range. Until the spell ends, the target\'s speed is doubled, it gains a +2 bonus to AC, it has advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.' },
  { name: 'Hunger of Hadar', level: 3, school: 'Conjuration', castingTime: '1 action', range: '150 feet', duration: 'Concentration, up to 1 minute', classes: ['Warlock'], description: 'You open a gateway to the dark between the stars, a region infested with unknown horrors. A 20-foot-radius sphere of blackness and bitter cold appears, centered on a point within range. The void is filled with a cacophony of soft whispers and slurping noises that can be heard up to 30 feet away. No light, magical or otherwise, can illuminate the area, and creatures fully within the area are blinded.' },
  { name: 'Hypnotic Pattern', level: 3, school: 'Illusion', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a Wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.' },
  { name: 'Lightning Bolt', level: 3, school: 'Evocation', castingTime: '1 action', range: 'Self (100-foot line)', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer'], description: 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.' },
  { name: 'Mass Healing Word', level: 3, school: 'Evocation', castingTime: '1 bonus action', range: '60 feet', duration: 'Instantaneous', classes: ['Cleric', 'Bard'], description: 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.' },
  { name: 'Plant Growth', level: 3, school: 'Transmutation', castingTime: '1 action or 8 hours', range: '150 feet', duration: 'Instantaneous', classes: ['Druid', 'Bard', 'Ranger'], description: 'This spell channels vitality into plants within a specific area. Using the 1-action version, plants in a 100-foot radius around a point you choose become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.' },
  { name: 'Protection from Energy', level: 3, school: 'Abjuration', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Cleric', 'Druid', 'Ranger', 'Artificer'], description: 'For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder.' },
  { name: 'Revivify', level: 3, school: 'Necromancy', castingTime: '1 action', range: 'Touch', duration: 'Instantaneous', classes: ['Cleric', 'Paladin', 'Artificer'], description: 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can\'t return to life a creature that has died of old age, nor can it restore any missing body parts.' },
  { name: 'Slow', level: 3, school: 'Transmutation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer'], description: 'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a Wisdom saving throw or be affected by this spell for the duration. An affected target\'s speed is halved, it takes a −2 penalty to AC and Dexterity saving throws, and it can\'t use reactions. On its turn, it can use either an action or a bonus action, not both.' },
  { name: 'Speak with Dead', level: 3, school: 'Necromancy', castingTime: '1 action', range: '10 feet', duration: '10 minutes', classes: ['Cleric', 'Bard'], description: 'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse must still have a mouth and can\'t be undead. The spell fails if the corpse was the target of this spell within the last 10 days. Until the spell ends, you can ask the corpse up to five questions.' },
  { name: 'Spirit Guardians', level: 3, school: 'Conjuration', castingTime: '1 action', range: 'Self (15-foot radius)', duration: 'Concentration, up to 10 minutes', classes: ['Cleric'], description: 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish. When you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature\'s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a Wisdom saving throw, taking 3d8 radiant (or necrotic) damage on a failed save.' },
  { name: 'Stinking Cloud', level: 3, school: 'Conjuration', castingTime: '1 action', range: '90 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Bard'], description: 'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration. Each creature that is completely within the cloud at the start of its turn must make a Constitution saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling.' },
  { name: 'Tongues', level: 3, school: 'Divination', castingTime: '1 action', range: 'Touch', duration: '1 hour', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Cleric', 'Bard'], description: 'This spell grants the creature you touch the ability to understand any spoken language it hears. Moreover, when the target speaks, any creature that knows at least one language and can hear the target understands what it says.' },
  { name: 'Vampiric Touch', level: 3, school: 'Necromancy', castingTime: '1 action', range: 'Self', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Warlock'], description: 'The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt.' },
  { name: 'Water Breathing', level: 3, school: 'Transmutation', castingTime: '1 action (ritual)', range: '30 feet', duration: '24 hours', classes: ['Wizard', 'Sorcerer', 'Druid', 'Ranger', 'Artificer'], description: 'This spell grants up to ten willing creatures you can see within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.' },

  // ── Level 4 ───────────────────────────────────────────────────────────────
  { name: 'Banishment', level: 4, school: 'Abjuration', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Cleric', 'Paladin'], description: 'You attempt to send one creature that you can see within range to another plane of existence. The target must succeed on a Charisma saving throw or be banished. If the target is native to the plane of existence you\'re on, you banish the target to a harmless demiplane. While there, the target is incapacitated.' },
  { name: 'Confusion', level: 4, school: 'Enchantment', castingTime: '1 action', range: '90 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Druid', 'Bard'], description: 'This spell assaults and twists creatures\' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere centered on a point you choose within range must succeed on a Wisdom saving throw when you cast this spell or be affected by it. Roll a d10 each turn to determine the confused creature\'s behavior.' },
  { name: 'Death Ward', level: 4, school: 'Abjuration', castingTime: '1 action', range: 'Touch', duration: '8 hours', classes: ['Cleric', 'Paladin'], description: 'You touch a creature and grant it a measure of protection from death. The first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends.' },
  { name: 'Dimension Door', level: 4, school: 'Conjuration', castingTime: '1 action', range: '500 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction. You can bring along objects as long as their weight doesn\'t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity.' },
  { name: 'Greater Invisibility', level: 4, school: 'Illusion', castingTime: '1 action', range: 'Touch', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Bard'], description: 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. Unlike the Invisibility spell, this version does not end if the target attacks or casts a spell.' },
  { name: 'Ice Storm', level: 4, school: 'Evocation', castingTime: '1 action', range: '300 feet', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer', 'Druid'], description: 'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a Dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one. The storm turns the ground in the area into difficult terrain until the end of your next turn.' },
  { name: 'Polymorph', level: 4, school: 'Transmutation', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 hour', classes: ['Wizard', 'Sorcerer', 'Druid', 'Bard'], description: 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a Wisdom saving throw to avoid the effect. The transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target\'s (or the target\'s level, if it doesn\'t have a challenge rating).' },
  { name: 'Wall of Fire', level: 4, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Druid'], description: 'You create a wall of fire on a solid surface within range. The wall can be up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration. When the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much damage on a successful save.' },

  // ── Level 5 ───────────────────────────────────────────────────────────────
  { name: 'Animate Objects', level: 5, school: 'Transmutation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Bard', 'Artificer'], description: 'Objects come to life at your command. Choose up to ten nonmagical objects within range that are not being worn or carried. Medium targets count as two objects, Large targets count as four objects, Huge targets count as eight objects. You can\'t animate any object larger than Huge. Each target animates and becomes a creature under your control until the spell ends or until reduced to 0 hit points.' },
  { name: "Bigby's Hand", level: 5, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Artificer'], description: 'You create a Large hand of shimmering, translucent force in an unoccupied space that you can see within range. The hand lasts for the spell\'s duration, and it moves at your command, mimicking the movements of your own hand. Choose one of the following forms: Clenched Fist (2d6+Mod force), Forceful Hand (push), Grasping Hand (grapple), or Interposing Hand (half speed, cover).' },
  { name: 'Commune', level: 5, school: 'Divination', castingTime: '1 minute (ritual)', range: 'Self', duration: '1 minute', classes: ['Cleric'], description: 'You contact your deity or a divine proxy and ask up to three questions that can be answered with a yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question.' },
  { name: 'Cone of Cold', level: 5, school: 'Evocation', castingTime: '1 action', range: 'Self (60-foot cone)', duration: 'Instantaneous', classes: ['Wizard', 'Sorcerer'], description: 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a Constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one. A creature killed by this spell becomes a frozen statue until it thaws.' },
  { name: 'Dominate Person', level: 5, school: 'Enchantment', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Bard'], description: 'You attempt to beguile a humanoid that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. While the target is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious.' },
  { name: 'Flame Strike', level: 5, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Cleric'], description: 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a Dexterity saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much damage on a successful one.' },
  { name: 'Hold Monster', level: 5, school: 'Enchantment', castingTime: '1 action', range: '90 feet', duration: 'Concentration, up to 1 minute', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Bard'], description: 'Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.' },
  { name: 'Mass Cure Wounds', level: 5, school: 'Evocation', castingTime: '1 action', range: '60 feet', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Bard'], description: 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.' },
  { name: 'Raise Dead', level: 5, school: 'Necromancy', castingTime: '1 hour', range: 'Touch', duration: 'Instantaneous', classes: ['Cleric', 'Bard', 'Paladin'], description: 'You return a dead creature you touch to life, provided that it has been dead no longer than 10 days. If the creature\'s soul is both willing and at liberty to rejoin the body, the creature returns to life with 1 hit point. This spell also neutralizes any poisons and cures nonmagical diseases that affected the creature at the time it died.' },
  { name: 'Scrying', level: 5, school: 'Divination', castingTime: '10 minutes', range: 'Self', duration: 'Concentration, up to 10 minutes', classes: ['Wizard', 'Sorcerer', 'Warlock', 'Cleric', 'Druid', 'Bard'], description: 'You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a Wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it.' },
  { name: 'Telekinesis', level: 5, school: 'Transmutation', castingTime: '1 action', range: '60 feet', duration: 'Concentration, up to 10 minutes', classes: ['Wizard', 'Sorcerer'], description: 'You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell, and as your action each round for the duration, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below. You can affect the same target round after round, or choose a new one at any time.' },
  { name: 'Teleportation Circle', level: 5, school: 'Conjuration', castingTime: '1 minute', range: '10 feet', duration: '1 round', classes: ['Wizard', 'Sorcerer', 'Bard'], description: 'As you cast the spell, you draw a 10-foot-diameter circle on the ground inscribed with sigils that link your location to a permanent teleportation circle of your choice whose sigil sequence you know and that is on the same plane of existence as you. A shimmering portal opens within the circle you drew and remains open until the end of your next turn.' },
  { name: 'Wall of Force', level: 5, school: 'Evocation', castingTime: '1 action', range: '120 feet', duration: 'Concentration, up to 10 minutes', classes: ['Wizard'], description: 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-by-10-foot panels. The wall is 1/4 inch thick. Each panel must be contiguous with at least one other panel.' },
];
